package com.restaurant.controller; import com.restaurant.common.ApiResponse; import com.restaurant.dto.payment.*; import com.restaurant.service.PaymentService; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.web.bind.annotation.*; import java.util.List; @RestController @RequestMapping("/payments") @RequiredArgsConstructor public class PaymentController { private final PaymentService service; @PostMapping public ApiResponse<PaymentResponse> create(@Valid @RequestBody PaymentCreateRequest r){return ApiResponse.ok("Payment created", service.create(r));} @GetMapping("/{id}") public ApiResponse<PaymentResponse> get(@PathVariable Long id){return ApiResponse.ok("Payment detail", service.get(id));} @GetMapping("/order/{orderId}") public ApiResponse<List<PaymentResponse>> byOrder(@PathVariable Long orderId){return ApiResponse.ok("Order payments", service.byOrder(orderId));} @PostMapping("/{id}/confirm") public ApiResponse<PaymentResponse> confirm(@PathVariable Long id,@RequestBody(required=false) PaymentConfirmRequest r){return ApiResponse.ok("Payment confirmed", service.confirm(id,r));} @PostMapping("/{id}/fail") public ApiResponse<PaymentResponse> fail(@PathVariable Long id){return ApiResponse.ok("Payment failed", service.fail(id));} @PostMapping("/{id}/refund") public ApiResponse<PaymentResponse> refund(@PathVariable Long id){return ApiResponse.ok("Payment refunded", service.refund(id));}}
